// =============================================================================
// ec2-instance.tpl.ts — Custom Alchemy resource for AWS EC2 instances
//
// This is the Alchemy resource definition (create / update / delete / replace).
// Lifecycle decision logic (should we replace? can we adopt legacy state?)
// lives in ec2-lifecycle.tpl.ts to keep this file focused on AWS API calls.
//
// Generated by stackpanel — static library code.
// =============================================================================
import type { Context } from "alchemy";
import { Resource } from "alchemy";
import {
  type Ec2Instance,
  type Ec2InstanceProps,
  type NormalizedEc2InstanceProps,
  coerceEc2InstanceState,
  isEc2InstanceReady,
  normalizeEc2InstanceProps,
  requiresEc2InstanceReplacement,
  shouldReuseEc2InstanceState,
} from "./ec2-lifecycle";

// Re-export types and helpers so existing imports from this module still work.
export {
  type Ec2Instance,
  type Ec2InstanceProps,
  type NormalizedEc2InstanceProps,
  coerceEc2InstanceState,
  isEc2InstanceReady,
  normalizeEc2InstanceProps,
  requiresEc2InstanceReplacement,
  shouldReuseEc2InstanceState,
};

// ---- AWS helpers ------------------------------------------------------------

/** Accept either an ARN or a profile name for the RunInstances API. */
function formatIamInstanceProfile(
  iamInstanceProfile: string | null | undefined,
): { Arn: string } | { Name: string } | undefined {
  if (!iamInstanceProfile) return undefined;
  return iamInstanceProfile.startsWith("arn:")
    ? { Arn: iamInstanceProfile }
    : { Name: iamInstanceProfile };
}

/** IAM instance profiles take a few seconds to propagate after creation. */
function isRetryableIamInstanceProfileError(err: unknown): boolean {
  if (!err || typeof err !== "object") return false;
  const name = "name" in err ? String((err as { name?: unknown }).name) : "";
  const message = "message" in err ? String((err as { message?: unknown }).message) : "";
  return (
    name === "InvalidParameterValue" &&
    /iamInstanceProfile\.(arn|name)/i.test(message) &&
    /Invalid IAM Instance Profile/i.test(message)
  );
}

async function runInstancesWithRetry(
  client: InstanceType<(typeof import("@aws-sdk/client-ec2"))["EC2Client"]>,
  command: import("@aws-sdk/client-ec2").RunInstancesCommand,
  attempts = 10,
): Promise<import("@aws-sdk/client-ec2").RunInstancesCommandOutput> {
  for (let attempt = 0; attempt < attempts; attempt += 1) {
    try {
      return await client.send(command);
    } catch (err) {
      if (!isRetryableIamInstanceProfileError(err) || attempt === attempts - 1) throw err;
      await new Promise((resolve) => setTimeout(resolve, 3000));
    }
  }
  throw new Error("Unable to create EC2 instance");
}

/** Poll DescribeInstances until the instance is running (and public, if applicable). */
async function waitForEc2InstanceDetails(
  client: InstanceType<(typeof import("@aws-sdk/client-ec2"))["EC2Client"]>,
  instanceId: string,
  requirePublicEndpoint: boolean,
  attempts = 40,
) {
  const { DescribeInstancesCommand } = await import("@aws-sdk/client-ec2");

  for (let attempt = 0; attempt < attempts; attempt += 1) {
    const described = await client.send(
      new DescribeInstancesCommand({ InstanceIds: [instanceId] }),
    );
    const instance = described.Reservations?.[0]?.Instances?.[0];
    if (isEc2InstanceReady(instance, requirePublicEndpoint)) return instance;
    await new Promise((resolve) => setTimeout(resolve, 3000));
  }

  throw new Error(`Timed out waiting for EC2 instance ${instanceId} to become ready`);
}

/** Diff-apply tags: remove stale keys, upsert current ones. */
async function syncInstanceTags(
  client: InstanceType<(typeof import("@aws-sdk/client-ec2"))["EC2Client"]>,
  instanceId: string,
  previous: Record<string, string>,
  next: Record<string, string>,
) {
  const { CreateTagsCommand, DeleteTagsCommand } = await import("@aws-sdk/client-ec2");

  const removedKeys = Object.keys(previous).filter((key) => !(key in next));
  if (removedKeys.length > 0) {
    await client.send(
      new DeleteTagsCommand({
        Resources: [instanceId],
        Tags: removedKeys.map((Key) => ({ Key })),
      }),
    );
  }

  if (Object.keys(next).length > 0) {
    await client.send(
      new CreateTagsCommand({
        Resources: [instanceId],
        Tags: Object.entries(next).map(([Key, Value]) => ({ Key, Value })),
      }),
    );
  }
}

// ---- Alchemy resource -------------------------------------------------------

export const Ec2Instance = Resource(
  "stackpanel::Ec2Instance",
  async function (
    this: Context<Ec2Instance>,
    _id: string,
    props: Ec2InstanceProps,
  ): Promise<Ec2Instance> {
    const {
      EC2Client,
      RunInstancesCommand,
      TerminateInstancesCommand,
    } = await import("@aws-sdk/client-ec2");

    const client = new EC2Client({});
    const propsSnapshot = normalizeEc2InstanceProps(props);

    // Attempt to read legacy Cloud Control state for migration scenarios.
    const migratedState = coerceEc2InstanceState(this.output);
    const reusableState = shouldReuseEc2InstanceState(this.phase, migratedState)
      ? migratedState
      : {};

    // -- Delete ---------------------------------------------------------------
    if (this.phase === "delete") {
      if (props.destroyOnDelete === false) return this.destroy();
      if (this.output?.instanceId) {
        await client.send(
          new TerminateInstancesCommand({ InstanceIds: [this.output.instanceId] }),
        );
      }
      return this.destroy();
    }

    // -- Replace check --------------------------------------------------------
    // Compare our stored snapshot against the new desired props.
    // Only triggers on actual immutable changes, not on AWS's synthetic fields.
    const previousSnapshot = this.output?.propsSnapshot ?? reusableState.propsSnapshot;
    if (
      this.phase === "update" &&
      previousSnapshot &&
      requiresEc2InstanceReplacement(previousSnapshot, propsSnapshot)
    ) {
      return this.replace();
    }

    // -- Create or adopt ------------------------------------------------------
    let instanceId = shouldReuseEc2InstanceState(this.phase, this.output)
      ? this.output?.instanceId
      : reusableState.instanceId;

    if (!instanceId) {
      const run = await runInstancesWithRetry(
        client,
        new RunInstancesCommand({
          ImageId: props.ami,
          InstanceType: props.instanceType,
          SubnetId: props.subnetId,
          SecurityGroupIds: props.securityGroupIds,
          KeyName: props.keyName ?? undefined,
          IamInstanceProfile: formatIamInstanceProfile(props.iamInstanceProfile),
          UserData: props.userData
            ? Buffer.from(props.userData).toString("base64")
            : undefined,
          MinCount: 1,
          MaxCount: 1,
          BlockDeviceMappings: props.rootVolumeSize
            ? [{ DeviceName: "/dev/xvda", Ebs: { VolumeSize: props.rootVolumeSize, VolumeType: "gp3" } }]
            : undefined,
          NetworkInterfaces: props.associatePublicIp === false
            ? [{ DeviceIndex: 0, SubnetId: props.subnetId, Groups: props.securityGroupIds, AssociatePublicIpAddress: false }]
            : undefined,
          TagSpecifications: [{
            ResourceType: "instance",
            Tags: Object.entries({
              Name: props.name,
              ...props.tags,
              alchemy_stage: this.stage,
              alchemy_resource: this.id,
            }).map(([Key, Value]) => ({ Key, Value })),
          }],
        }),
      );
      instanceId = run.Instances?.[0]?.InstanceId;
    }

    if (!instanceId) throw new Error(`Unable to create EC2 instance ${props.name}`);

    // -- Tag sync -------------------------------------------------------------
    if (this.phase === "update") {
      await syncInstanceTags(client, instanceId, previousSnapshot?.tags ?? {}, propsSnapshot.tags);
    } else if (Object.keys(propsSnapshot.tags).length > 0) {
      await syncInstanceTags(client, instanceId, {}, propsSnapshot.tags);
    }

    // -- Wait for readiness ---------------------------------------------------
    const instance = await waitForEc2InstanceDetails(
      client,
      instanceId,
      propsSnapshot.associatePublicIp,
    );

    return {
      instanceId,
      publicIp: instance?.PublicIpAddress ?? null,
      privateIp: instance?.PrivateIpAddress ?? null,
      publicDns: instance?.PublicDnsName ?? null,
      state: instance?.State?.Name ?? null,
      name: props.name,
      propsSnapshot,
    };
  },
);
